"use client";

import { useState, useRef } from "react";
import { Autocomplete, useJsApiLoader } from "@react-google-maps/api";
import { ENDPOINTS } from "../app/config";

const libraries: "places"[] = ["places"];

export default function RegistroEstablecimiento() {
  const { isLoaded } = useJsApiLoader({
    id: "google-map-script",
    googleMapsApiKey: process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY || "",
    libraries,
  });

  const [loading, setLoading] = useState(false);
  const autocompleteRef = useRef<google.maps.places.Autocomplete | null>(null);

  const [formData, setFormData] = useState({
    nombre_comercio: "",
    categoria: "",
    direccion: "",
    municipio: "",
    provincia: "",
    cp: "",
    telefono: "",
    correo: "",
    latitud: 0,
    longitud: 0,
  });

  const onPlaceChanged = () => {
    const place = autocompleteRef.current?.getPlace();
    if (!place || !place.address_components || !place.geometry) return;

    const coords = place.geometry.location;
    let addressInfo = {
      direccion: place.name || "",
      cp: "",
      municipio: "",
      provincia: "",
    };

    place.address_components.forEach((component) => {
      const types = component.types;
      if (types.includes("postal_code")) addressInfo.cp = component.long_name;
      if (types.includes("locality"))
        addressInfo.municipio = component.long_name;
      if (types.includes("administrative_area_level_2"))
        addressInfo.provincia = component.long_name;
    });

    setFormData((prev) => ({
      ...prev,
      direccion: addressInfo.direccion,
      cp: addressInfo.cp,
      municipio: addressInfo.municipio,
      provincia: addressInfo.provincia,
      latitud: coords?.lat() || 0,
      longitud: coords?.lng() || 0,
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await fetch(`${ENDPOINTS.ESTABLECIMIENTOS}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        alert("¡Establecimiento registrado con éxito!");
      } else {
        alert("Error al guardar en el servidor.");
      }
    } catch (error) {
      alert("Error de conexión.");
    } finally {
      setLoading(false);
    }
  };

  if (!isLoaded)
    return (
      <div className="container text-center p-5">
        <h3>Cargando mapa...</h3>
      </div>
    );

  return (
    <div className="container-fluid min-vh-100 d-flex align-items-center justify-content-center bg-light py-5">
      <div
        className="card shadow-lg border-0 rounded-4"
        style={{ maxWidth: "500px", width: "100%", backgroundColor: "#1a4d4a" }}
      >
        <div className="card-body p-4 p-md-5 text-white">
          <div className="text-center mb-4">
            <div className="bg-white d-inline-block p-3 rounded-circle mb-3 shadow">
              <span style={{ fontSize: "2rem" }}>🏬</span>
            </div>
            <h2 className="fw-bold">Registra tu Comercio</h2>
            <p className="text-light opacity-75 small">
              Tus coordenadas se calcularán automáticamente
            </p>
          </div>

          <form onSubmit={handleSubmit}>
            {/* Nombre */}
            <div className="mb-3">
              <label className="form-label small fw-bold">
                Nombre del Comercio
              </label>
              <input
                type="text"
                required
                className="form-control form-control-lg bg-transparent text-white border-secondary shadow-none"
                style={{ borderColor: "#40916c !important" }}
                onChange={(e) =>
                  setFormData({ ...formData, nombre_comercio: e.target.value })
                }
              />
            </div>

            {/* Google Autocomplete */}
            <div className="mb-3">
              <label className="form-label small fw-bold">
                Busca tu Dirección *
              </label>
              <Autocomplete
                onLoad={(ref) => (autocompleteRef.current = ref)}
                onPlaceChanged={onPlaceChanged}
                options={{
                  types: ["address"],
                  componentRestrictions: { country: "es" },
                }}
              >
                <input
                  type="text"
                  placeholder="Empieza a escribir tu calle..."
                  required
                  className="form-control form-control-lg bg-transparent text-white border-secondary shadow-none"
                />
              </Autocomplete>
            </div>

            {/* Municipio y CP */}
            <div className="row g-3 mb-3">
              <div className="col-6">
                <label
                  className="form-label small opacity-75 text-uppercase"
                  style={{ fontSize: "10px" }}
                >
                  Municipio
                </label>
                <input
                  readOnly
                  value={formData.municipio}
                  className="form-control form-control-sm bg-dark bg-opacity-25 text-white border-0"
                />
              </div>
              <div className="col-6">
                <label
                  className="form-label small opacity-75 text-uppercase"
                  style={{ fontSize: "10px" }}
                >
                  C. Postal
                </label>
                <input
                  readOnly
                  value={formData.cp}
                  className="form-control form-control-sm bg-dark bg-opacity-25 text-white border-0"
                />
              </div>
            </div>

            {/* Correo */}
            <div className="mb-4">
              <label className="form-label small fw-bold">
                Correo electrónico
              </label>
              <input
                type="email"
                placeholder="ejemplo@correo.com"
                className="form-control form-control-lg bg-transparent text-white border-secondary shadow-none"
                onChange={(e) =>
                  setFormData({ ...formData, correo: e.target.value })
                }
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="btn btn-warning btn-lg w-100 fw-bold py-3 shadow"
              style={{ backgroundColor: "#f6bd60", color: "#1a4d4a" }}
            >
              {loading ? "PROCESANDO..." : "FINALIZAR REGISTRO"}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
